package org.mockito.internal.stubbing.defaultanswers;

import cucumber.api.junit.Cucumber;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
public class CucumberTest {
    // This is the JUnit runner for Cucumber scenarios
}

package org.mockito.internal.stubbing.defaultanswers.steps;

import cucumber.api.java.en.Given;
import cucumber.api.java.en.When;
import cucumber.api.java.en.Then;
import org.mockito.Mockito;
import static org.junit.Assert.assertEquals;

public class StepDefs {

    private Comparable mockComparable;
    private Integer result;

    @Given("^a mock object that implements Comparable$")
    public void a_mock_object_that_implements_Comparable() throws Throwable {
        mockComparable = Mockito.mock(Comparable.class);
    }

    @When("^the \"compareTo\" method is called with the mock object itself as the argument$")
    public void the_compareTo_method_is_called_with_the_mock_object_itself_as_the_argument() throws Throwable {
        try {
            // This should return 0 when comparing a mock to itself
            // In the bug case, this might not return 0 as expected
            result = mockComparable.compareTo(mockComparable);
        } catch (Exception e) {
            // In case of exception, set result to a special value to indicate this
            result = Integer.MIN_VALUE; // Special indicator for exception
        }
    }

    @Then("^the result should be (\\d+)$")
    public void the_result_should_be(int expected) throws Throwable {
        assertEquals("The compareTo method should return " + expected + " when comparing mock to itself", 
                    expected, result.intValue());
    }
}
